    ('OPT-V 569', 'SELECTED STUDIES', '13167', 'Class Status', NULL, NULL, 'Shirin Hassan', 5, NULL, 'Independent Study', '1–8', NULL, ARRAY[]::TEXT[], 'Items of current scientific interest. Consideration given to student''s special interests. May include writing of abstracts and reviews of current visual science literature.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 607', 'CONSULTING PRACTICUM IN THE BUSINESS OF OPTOMETRY', '9273', 'Class Status', NULL, 'WB WEB', 'Neil Pence, Todd Peabody', 2, NULL, 'Practicum', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The Consulting Practicum in the Business of Optometry consists of a quarter-long integrated class and consulting engagement with a practice partner. The course aims to build the critical and transferrable management consulting skills.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 610', 'STRATEGIC PROFIT ANALYSIS IN OPTOMETRIC PRACTICE', '36804', 'Class Status', 'Non Standard Session', 'WB WEB', 'Neil Pence, Todd Peabody', 4, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Examine the strategy, tools and mechanisms needed to perform profit analysis of an optometric practice. The goal is to identify, analyze, and maximize the profit potential of an optometric practice by breaking down the various components of the practice and exploring the best practice options for each office area.', ARRAY[]::TEXT[], NULL),
