    ('OPT-V 644', 'OCULAR DISEASE I: ANTERIOR SEGMENT', '13293', 'Class Status', 'Tu Tuesday 10:00 AM–11:50 AM', 'OP 111 OP 105', 'Jane Ann Grogg', 15, NULL, 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'A detailed description of the signs, symptoms, differential diagnosis, and an introduction to management of ocular diseases of the anterior segment.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 646', 'OCULAR PHARMACOLOGY', '13294', 'Class Status', 'W Wednesday 10:00 AM–10:50 AM', 'OP 105 OP 105', 'Nikole Himebaugh, Stephanie Klemencic', 17, NULL, 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'This course includes in-depth study of the mechanisms of action, clinical indications, ocular side effects, systemic side effects, and contraindications of pharmacological agents used in the diagnosis and treatment of ocular disease.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 652', 'CLINICAL SCIENCES III: ACCOMODATION AND BINOCULAR VISION', '4021', 'Class Status', 'M Monday 12:00 PM–1:50 PM', 'OP 105', 'Kimberly Kohne, Katie Connolly', 3, 'Lecture', 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Vision examination techniques and theory and application of vision testing instrumentation, with emphasis on accommodation and binocular vision; accommodation and vergence test findings as they relate to normal function, subjective symptoms, and performance; theory and case analysis of non-strabismic binocular vision problems.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 652', 'CLINICAL SCIENCES III: ACCOMODATION AND BINOCULAR VISION', '4022', 'Class Status', 'M Monday 2:00 PM–3:50 PM', 'OP 101', 'Kimberly Kohne, Katie Connolly', 2, 'Laboratory', 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Vision examination techniques and theory and application of vision testing instrumentation, with emphasis on accommodation and binocular vision; accommodation and vergence test findings as they relate to normal function, subjective symptoms, and performance; theory and case analysis of non-strabismic binocular vision problems.', ARRAY[]::TEXT[], NULL),
