    ('OPT-V 652', 'CLINICAL SCIENCES III: ACCOMODATION AND BINOCULAR VISION', '9345', 'Closed', 'Th Thursday 4:00 PM–5:50 PM', 'OP 101', 'Kimberly Kohne, Katie Connolly', 0, 'Laboratory', 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Vision examination techniques and theory and application of vision testing instrumentation, with emphasis on accommodation and binocular vision; accommodation and vergence test findings as they relate to normal function, subjective symptoms, and performance; theory and case analysis of non-strabismic binocular vision problems.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 653', 'CLINICAL SCIENCES III: POSTERIOR SEGMENT EXAMINATION TECHNIQUES', '4551', 'Closed', 'Tu Tuesday 12:00 PM–12:50 PM', 'OP 111', 'Christopher Clark', 0, 'Lecture', 'Lecture', '2', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Introduction to techniques used to examine and evaluate the health of the posterior sement of the eye, including direct ophthalmoscopy, monocular and binocular indirect ophthalmoscopy, fundus, biomicroscopy, three mirror gonioscopy and posterior pole imagin techniques. Other technuques will be introduced as appropriate.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 653', 'CLINICAL SCIENCES III: POSTERIOR SEGMENT EXAMINATION TECHNIQUES', '4552', 'Closed', 'Tu Tuesday 1:00 PM–2:00 PM', 'OP 106', 'Christopher Clark', 0, 'Laboratory', 'Lecture', '2', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Introduction to techniques used to examine and evaluate the health of the posterior sement of the eye, including direct ophthalmoscopy, monocular and binocular indirect ophthalmoscopy, fundus, biomicroscopy, three mirror gonioscopy and posterior pole imagin techniques. Other technuques will be introduced as appropriate.', ARRAY[]::TEXT[], NULL),
