    ('OPT-V 653', 'CLINICAL SCIENCES III: POSTERIOR SEGMENT EXAMINATION TECHNIQUES', '4556', 'Closed', 'W Wednesday 3:10 PM–4:10 PM', 'OP 106', 'Christopher Clark', 0, 'Laboratory', 'Lecture', '2', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Introduction to techniques used to examine and evaluate the health of the posterior sement of the eye, including direct ophthalmoscopy, monocular and binocular indirect ophthalmoscopy, fundus, biomicroscopy, three mirror gonioscopy and posterior pole imagin techniques. Other technuques will be introduced as appropriate.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 653', 'CLINICAL SCIENCES III: POSTERIOR SEGMENT EXAMINATION TECHNIQUES', '4709', 'Closed', 'Th Thursday 2:00 PM–3:00 PM', 'OP 106', 'Christopher Clark', 0, 'Laboratory', 'Lecture', '2', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Introduction to techniques used to examine and evaluate the health of the posterior sement of the eye, including direct ophthalmoscopy, monocular and binocular indirect ophthalmoscopy, fundus, biomicroscopy, three mirror gonioscopy and posterior pole imagin techniques. Other technuques will be introduced as appropriate.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 653', 'CLINICAL SCIENCES III: POSTERIOR SEGMENT EXAMINATION TECHNIQUES', '4710', 'Closed', 'Th Thursday 5:30 PM–6:45 PM', 'GA 0005', 'Christopher Clark', 0, 'Laboratory', 'Lecture', '2', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Introduction to techniques used to examine and evaluate the health of the posterior sement of the eye, including direct ophthalmoscopy, monocular and binocular indirect ophthalmoscopy, fundus, biomicroscopy, three mirror gonioscopy and posterior pole imagin techniques. Other technuques will be introduced as appropriate.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 655', 'OPTOMETRIC PROFESSION II', '7233', 'Class Status', 'F Friday 9:00 AM–9:50 AM', 'OP 111', 'Todd Peabody, Neil Pence', 16, NULL, 'Seminar', '0.5', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'This seminar course is a continuation of Optometric Profession I. Content includes history, fundamentals and principles of public health, optometry''s role in the healthcare community, professionalism and ethics, cultural competency, current issues and professional affairs, licensure and scope of practice, and professional development.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 678', 'OPHTHALMIC DISPENSING CLINIC', '6892', 'Class Status', NULL, NULL, 'Nikole Himebaugh', 17, NULL, 'Clinic', '2', NULL, ARRAY[]::TEXT[], 'Clinical experience in appropriate frame and lens selection, facial measurement for eye wear fitting, verification of finished prescription accuracy and spectacle alignment, adjusting and dispensing of eye wear for comfort and optical accuracy, and repair of eyewear.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 701', 'GRAND ROUNDS I', '4246', 'Class Status', NULL, NULL, 'Susan Kovacich', 12, NULL, 'Lecture', '0.5', NULL, ARRAY[]::TEXT[], 'First course in a two-semester sequence for beginning clinical interns. Addresses different approaches in the diagnosis and management of complex cases given limited clinical information. Presentations of unique cases by practitioners and residents in each of the following areas: Binocular Vision/Pediatrics, Contact Lenses, Ocular Disease, and Primary Care.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 746', 'OCULAR DISEASE IV: NEUROLOGICAL DISEASES', '29954', 'Class Status', 'Tu Tuesday 8:00 AM–9:50 AM', 'OP 111', 'Patricia Henderson', 12, NULL, 'Lecture', '2', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'A detailed discussion of the signs, symptoms, differential diagnosis, and management of neurological diseases affecting the eye.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 748', 'PRINCIPLES AND METHODS OF PHYSICAL ASSESSMENT AND MEDICINE', '2732', 'Class Status', 'M Monday 8:00 AM–9:50 AM', 'OP 105 OP 111', 'Kimberly Kohne', 12, 'Lecture', 'Lecture', '3.5', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Comprehensive health history, physical examination with emphasis on HEENT and neurological screening, and their relationship to ocular health conditions and medical management; clinical chemistry and interpretation of clinical laboratory tests; criteria for referral to other providers; principles of CPR and emergency office procedures.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 748', 'PRINCIPLES AND METHODS OF PHYSICAL ASSESSMENT AND MEDICINE', '2733', 'Class Status', 'MTh Monday, Thursday 6:30 PM–7:20 PM', 'OP 105', 'Kimberly Kohne', 12, 'Laboratory', 'Lecture', '3.5', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Comprehensive health history, physical examination with emphasis on HEENT and neurological screening, and their relationship to ocular health conditions and medical management; clinical chemistry and interpretation of clinical laboratory tests; criteria for referral to other providers; principles of CPR and emergency office procedures.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 756', 'CLINICAL ASSESSMENT I', '2734', 'Class Status', 'W Wednesday 8:00 AM–8:50 AM', 'OP 111', 'Neil Pence, Don Faimon', 12, NULL, 'Lecture', '1', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Introduction to clinical reasoning and formulation of differential diagnostic protocols for investigation of various visual problems.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 758', 'MANAGEMENT OF AMBLYOPIA AND STRABISMUS', '8379', 'Closed', 'W Wednesday 10:30 AM–12:20 PM', 'OP 111', 'Don Lyon', 0, 'Lecture', 'Lecture', '2.5', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'This course builds upon previous topics in pediatrics and binocular vision and introduces two main topics: diagnosis and treatment of amblyopia, and the treatment of strabismus. The course will wrap up with treatment options for Persistent Post-Concussion Syndrome and visual information processing deficits.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 758', 'MANAGEMENT OF AMBLYOPIA AND STRABISMUS', '8380', 'Closed', 'Th Thursday 8:00 AM–9:50 AM', 'OP 202', 'Don Lyon', 0, 'Laboratory', 'Lecture', '2.5', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'This course builds upon previous topics in pediatrics and binocular vision and introduces two main topics: diagnosis and treatment of amblyopia, and the treatment of strabismus. The course will wrap up with treatment options for Persistent Post-Concussion Syndrome and visual information processing deficits.', ARRAY[]::TEXT[], NULL),
