    ('OPT-V 780', 'CLIN SKILLS ENHANCEMENT-3RD YR', '2735', 'Class Status', NULL, NULL, 'Jeffrey Perotti', 2, NULL, 'Clinic', '2', NULL, ARRAY[]::TEXT[], 'Increased supervision provided by clinical faculty for students having difficulty in areas of clinical performance.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 782', 'PRESERVATION OF CLINICAL SKILLS', '6362', 'Class Status', NULL, NULL, 'Jeffrey Perotti', 5, NULL, 'Clinic', '3–5', NULL, ARRAY[]::TEXT[], 'Supervision by Clinical Faculty on the clinic floor for students who did not receive a passing grade in a third year didactic course. Allows students to maintain clinical knowledge while they are completing third year coursework.', ARRAY[]::TEXT[], NULL),
