    ('OVST-Z 499', 'EDUCATION ABROAD IN SCOTLAND', '33765', 'Class Status', NULL, NULL, 'Susan Carty', 28, NULL, 'Lecture', '15', NULL, ARRAY[]::TEXT[], 'Used as an administrative course number to enroll students accepted to study in Scotland.', ARRAY[]::TEXT[], NULL),
    ('PACE-C 100', 'LEADERS AND LEADERSHIP', '7791', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'LH 004', 'Stephen Volan', 5, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'An interdisciplinary introduction to concepts of leaders and leadership. Includes research, comparison and analysis of different leaders and leadership styles; examines how the history and theories of leadership evolved; and covers how leaders thrive in different cultural settings, typically in strong relationship with followers.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('PACE-C 200', 'ISSUE FORUM', '9436', 'Class Status', NULL, 'Sa Saturday 11:00 AM–4:30 PM Non Standard Session 9/15/2025–12/19/2025', 'WH 101', NULL, NULL, 'Practice', '1', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Dialogue and deliberation activities structured as a half-day forum during which participants interact with an expert panel and discuss a current controversial issue previously selected by PACE student leaders. Includes a pre-forum assignment, active participation in the forum, and a post-forum response paper.', ARRAY['Class uses IU eTexts'], NULL),
    ('PACE-C 250', 'LEADERSHIP AND PUBLIC POLICY', '5643', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 208', 'Mark Fraley', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Interdisciplinary introduction to American public leadership and policy making. Explores theoretical and empirical work on American politics and civil society from the local community to the nation''s capital. Introduces skills of effective political and civic engagement.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('PACE-C 250', 'LEADERSHIP AND PUBLIC POLICY', '6113', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 306', 'Mark Fraley', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Interdisciplinary introduction to American public leadership and policy making. Explores theoretical and empirical work on American politics and civil society from the local community to the nation''s capital. Introduces skills of effective political and civic engagement.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('PACE-C 440', 'FORUM DISCUSSION LEADER', '9435', 'Class Status', 'Sep 20', 'Sa Saturday 10:00 AM–4:00 PM Sa Saturday 10:00 AM–4:00 PM Sa Saturday 10:00 AM–4:00 PM F Friday 1:55 PM–4:00 PM F Friday 1:55 PM–4:00 PM F Friday 1:55 PM–4:00 PM Sa Saturday 9:00 AM–6:00 PM Sa Saturday 9:00 AM–6:00 PM Sa Saturday 9:00 AM–6:00 PM Sa Saturday 9:00 AM–6:00 PM Sa Saturday 9:00 AM–6:00 PM Sa Saturday 9:00 AM–6:00 PM Sa Saturday 9:00 AM–6:00 PM F Friday 1:15 PM–2:45 PM Non Standard Session 9/20/2025–10/10/2025', 'WH 007 WH 008 WH 009 WH 100 WH 002 WH 005 WH 101 WH 104 WH 106 WH 110 WH 112 WH 114 WH 116 WH 009', NULL, NULL, 'Practice', '1', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Training in facilitation of democratic deliberation as preparation for leading small group discussions for the PACE Issue Forum. Includes training, practice, service at the Issue Forum, and debriefing meeting. Final reflection paper required.', ARRAY[]::TEXT[], NULL),
    ('PACE-S 250', 'HONORS LEADERSHIP AND PUBLIC POLICY', '9434', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 306', 'Mark Fraley', 2, NULL, 'Discussion', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Interdisciplinary introduction to American public leadership and policy making. Explores theoretical and empirical work on American politics and civil society from the local community to the nation''s capital. Introduces skills of effective political and civic engagement.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('PACE-X 378', 'APPLIED RESEARCH: LEGAL SYSTEMS IN INDIANA', '33926', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'CG 2077', 'Angie Raymond', 0, NULL, 'Research', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Supports the Indiana Supreme Court''s desire to understand and improve the cost, efficiency, and access of the civil legal system. Students review legal data, design research questions, and meet with stakeholders. They also engage in field research, including observing courtroom proceedings, running focus groups, and assisting a legal aid organization.', ARRAY[]::TEXT[], NULL),
    ('PACE-X 473', 'INTERNSHIP IN POLITICAL AND CIVIC ENGAGEMENT', '4707', 'Class Status', NULL, NULL, 'Mark Fraley', 20, NULL, 'Internship', '1', NULL, ARRAY[]::TEXT[], 'Students will complete a mentored internship providing field experience in political and civic engagement. Includes an orientation session before and a structured evaluation afterward.', ARRAY[]::TEXT[], NULL),
    ('PACE-X 473', 'INTERNSHIP IN POLITICAL AND CIVIC ENGAGEMENT', '8902', 'Class Status', NULL, NULL, 'Mark Fraley', 5, NULL, 'Internship', '1', NULL, ARRAY[]::TEXT[], 'Students will complete a mentored internship providing field experience in political and civic engagement. Includes an orientation session before and a structured evaluation afterward.', ARRAY[]::TEXT[], NULL),
    ('PACE-X 490', 'READINGS IN POLITICAL AND CIVIC ENGAGEMENT', '4708', 'Class Status', NULL, NULL, 'Lisa-Marie Napoli', 10, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent readings under the supervision of an approved faculty mentor.', ARRAY[]::TEXT[], NULL),
    ('PHIL-G 599', 'THESIS RESEARCH', '3130', 'Class Status', NULL, NULL, 'Adam Leite', 3, NULL, 'Research', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
    ('PHIL-G 901', 'ADVANCED RESEARCH', '2804', 'Class Status', NULL, NULL, 'Adam Leite', 15, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('PHIL-M 302', 'ETHICS AND RESPONSIBLE MANAGEMENT', '10289', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'M2 100', 'John Robison', 2, NULL, 'Lecture', '3', 'IU MUSEUM OF ARCHAEOLOGY & ANT', ARRAY[]::TEXT[], 'Addresses the ethical dimensions of management and social responsibilities within the public and private sectors. Examines the legal and regulatory requirements of ethical conduct, including the establishment and use of codes of conduct by various organizations and industry groups. Particular emphasis placed on examining the processes managers may use to confront conflicts that arise in organizational settings between individual values and organizational goals. Evaluates case studies involving alleged breaches of ethical conduct.', ARRAY[]::TEXT[], NULL),
    ('PHIL-P 105', 'CRITICAL THINKING', '14879', 'Closed', 'TuTh Tuesday, Thursday 3:10 PM–4:00 PM', 'AC C114', 'Calum McNamara', 0, 'Lecture', 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'We spend a good part of our waking hours thinking and/or critiquing the thoughts and beliefs of ourselves and others. This course is designed to help you develop a toolbox of techniques and skills that will help you become a skilled evaluator and creator of arguments.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
