    ('PHSL-P 515', 'BASIC HUMAN PHYSIOLOGY FOR EDUCATORS', '9341', 'Class Status', 'MTuThF Monday, Tuesday, Thursday, Friday 8:00 AM–8:50 AM', 'BH 013', 'Pat Clark', 3, NULL, 'Lecture', '5', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Systems-based human physiology course designed for graduate students who will be teaching basic undergraduate human physiology. Lecture meets 4 times weekly, and a 3-hr lab meets weekly.', ARRAY[]::TEXT[], NULL),
