    ('PHYS-P 105', 'BASIC PHYSICS OF SOUND', '2818', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'SW 007', 'Jon Urheim', 36, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Physical principles involved in the description, generation, and reproduction of sound. Topics include physics of vibrations and waves, propagation, Fourier decomposition of complex wave forms, harmonic spectra, standing waves and resonance, sound loudness and decibels, room acoustics, analog/digital recording/reproduction. For interested students, P109 is an optional companion laboratory course.', ARRAY['IUB GenEd N&M credit - Natural Science
COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('PHYS-P 133', 'PHYSICS FOR FUTURE LEADERS', '11488', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'SW 208', 'Paul Sokol', 0, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Physics developments have led to technologies such as the internet and cell phones. This course introduces physics concepts and fields of research and future developments they may enable and provides a foundation to evaluate the technological, economic, and societal impacts of such developments. Designed primarily for students in non-science fields.', ARRAY['IUB GenEd N&M credit - Natural Science'], NULL),
