    ('PHYS-P 301', 'PHYSICS 3', '2871', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'SE 240', 'Tanaz Mohayai', 12, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'Third semester of a three-semester sequence. Special theory of relativity; introduction to quantum physics; atomic, nuclear, condensed matter, and elementary particle physics. Intended for science and mathematics majors. Three lecture-discussion periods each week.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('PHYS-P 309', 'MODERN PHYSICS LABORATORY', '2872', 'Class Status', 'Tu Tuesday 1:15 PM–5:15 PM', 'SW 137', 'Caryn Palatchi', 8, NULL, 'Laboratory', '3', 'SWAIN WEST', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('PHYS-P 331', 'THEORY OF ELECTRICITY AND MAGNETISM I', '2874', 'Closed', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'SE 240', 'Sima Setayeshgar', 0, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], NULL, ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('PHYS-P 400', 'ANALOG AND DIGITAL ELECTRONICS', '14001', 'Class Status', 'MW Monday, Wednesday 1:55 PM–2:45 PM', 'SW 217 SW 102', 'Walter Pettus, Anna Reine', 7, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Practical electronics as would be encountered in a research laboratory or industrial setting. Both analog (filters, power wupplies, transistors, amplifiers, op-amps, comparators, oscillators, transducers including the analysis of circuits using computer aided techniques) and digital devices, storage elements, discrete gates, and programmable devices.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('PHYS-P 410', 'COMPUTING APPLICATIONS IN PHYSICS', '9843', 'Closed', 'MWF Monday, Wednesday, Friday 10:15 AM–11:05 AM', 'SW 246A', 'Chris Meyer', 0, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], NULL, ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('PHYS-P 441', 'ANALYTICAL MECHANICS 1', '2875', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'SE 240', 'Matthew Shepherd', 8, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'Elementary mechanics of particles and rigid bodies, treated by methods of calculus and differential equations.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('PHYS-P 451', 'EXPERIMENTS IN MODERN PHYSICS I', '6361', 'Class Status', 'Tu Tuesday 12:45 PM–4:45 PM', 'SW 125', 'David Baxter', 2, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Advanced laboratory for senior physics majors. Experimental investigations and selected topics in nuclear, atomic and solid state physics.', ARRAY[]::TEXT[], NULL),
    ('PHYS-P 454', 'MODERN PHYSICS', '31067', 'Class Status', 'MWF Monday, Wednesday, Friday 2:20 PM–3:35 PM', 'SW 214', 'Raymond Co', 11, NULL, 'Lecture', '4', 'SWAIN WEST', ARRAY[]::TEXT[], 'Structure of multi-electron atoms. Experimental facts and theoretical models in solid state physics, nuclear physics, and elementary particle physics', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('PHYS-P 500', 'PHYSICS COLLOQUIUM', '8495', 'Class Status', 'W Wednesday 4:00 PM–5:00 PM', 'SW 119', 'William Snow', 70, NULL, 'Colloquium', '1', 'SWAIN WEST', ARRAY[]::TEXT[], 'General lecture by invited speakers and staff on recent research and discovery in physics.', ARRAY[]::TEXT[], NULL),
    ('PHYS-P 504', 'PRACTICUM IN PHYSICS LABORATORY INSTRUCTION', '2876', 'Class Status', 'F Friday 3:10 PM–4:00 PM', 'SW 109', 'Mark Messier', 13, NULL, 'Independent Study', '1', 'SWAIN WEST', ARRAY[]::TEXT[], 'Practical aspects of teaching physics labs. Meets the week before classes and one hour per week during the semester to discuss goals, effective teaching techniques, grading standards, AI/student relations, and administrative procedures as applied to P201.', ARRAY[]::TEXT[], NULL),
    ('PHYS-P 506', 'ELECTRICITY AND MAGNETISM I', '2877', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:40 PM', 'SW 220', 'William Snow', 11, NULL, 'Lecture', '4', 'SWAIN WEST', ARRAY[]::TEXT[], 'Three hours of lectures and one hour of recitation of the Development of Maxwell''s equations. Conservation laws. Problems in electrostatics and magnetostatics. Introduction to the special functions of mathematical physics. Time-dependent solutions of Maxwell''s equations. Motion of particles in given electromagnetic fields. Elementary theory of radiation. Plane waves in dielectric and conduction media. Dipole and quanrupole radiation from non-relativistic systems.', ARRAY[]::TEXT[], NULL),
    ('PHYS-P 511', 'QUANTUM MECHANICS I', '2879', 'Class Status', 'TuTh Tuesday, Thursday 9:10 AM–11:15 AM', 'SW 218', 'Herbert Fertig', 8, NULL, 'Lecture', '4', 'SWAIN WEST', ARRAY[]::TEXT[], 'Three hours of lectures and one hour of recitation. Basic principles, the Schrodinger equation, wave functions and physical interpretation. Bound and continuum states in one-dimensional systems. Bound states in central potential; hyrogen atom. Variational method. Time-independent perturbation theory.', ARRAY[]::TEXT[], NULL),
    ('PHYS-P 521', 'CLASSICAL MECHANICS', '2880', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'SW 217', 'Gerardo Ortiz', 10, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Vector and tensor analysis. Lagrangian and Hamiltonian dynamics. Conservation laws and variational principles. Two-body motion, many-particle systems, rigid-body motion. Canonical transformations and Hamilton-Jacobi theory. Continuum mechanics with introduction to complex variables.', ARRAY[]::TEXT[], NULL),
    ('PHYS-P 540', 'DIGITAL ELECTRONICS', '14003', 'Class Status', 'MW Monday, Wednesday 1:55 PM–2:45 PM', 'SW 217 SW 102', 'Walter Pettus, Anna Reine', 7, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Digital logic, storage elements, timing elements, arithmetic devices, digital-to-analog and analog-to-digital conversion. Course has lectures and labs emphasizing design, construction and analysis of circuits using discrete gates and programmable devices.', ARRAY[]::TEXT[], NULL),
    ('PHYS-P 551', 'MODERN PHYSICS LABORATORY', '6227', 'Class Status', 'Tu Tuesday 12:45 PM–4:45 PM', 'SW 125', 'David Baxter', 2, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Graduate-level laboratory: experiments on selected aspects of atomic, condensed-matter, and nuclear physics.', ARRAY[]::TEXT[], NULL),
    ('PHYS-P 555', 'QUANTUM COMPUTATION AND INFORMATION', '13946', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'SW 218', 'Phil Richerme', 9, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'The course covers basic concepts in quantum computation and information including: standard qubit model of computation, quantum algorithms such as Shor''s factoring and Grover''s search algorithms, physics of information processing, quantum error correction, and physical implementations of quantum computers.', ARRAY[]::TEXT[], NULL),
    ('PHYS-P 557', 'SOLID STATE PHYSICS', '31068', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'SW 103', 'Ceren Dag', 18, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Atomic theory of solids. Crystal and band theory. Thermal and electromagnetic properties of periodic structures.', ARRAY[]::TEXT[], NULL),
    ('PHYS-P 609', 'COMPUTATIONAL PHYSICS', '9841', 'Closed', 'MWF Monday, Wednesday, Friday 10:15 AM–11:05 AM', 'SW 246A', 'Chris Meyer', 0, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Designed to introduce students 1) to numerical methods for quadrature, solution of integral and differential equations, and linear algebra, 2) to the use of computation and computer graphics to simulate the behavior of complex physical systems. The precise choice of topics will vary.', ARRAY[]::TEXT[], NULL),
    ('PHYS-P 621', 'RELATIVISTIC QUANTUM FIELD THEORY I', '2881', 'Class Status', 'TuTh Tuesday, Thursday 10:15 AM–12:10 PM', 'SW 217', 'Radovan Dermisek', 3, NULL, 'Lecture', '4', 'SWAIN WEST', ARRAY[]::TEXT[], 'Introduction to quantum field theory; symmetries; Feynman diagrams; quantum electrodynamics and renormalization.', ARRAY[]::TEXT[], NULL),
    ('PHYS-P 637', 'THEORY OF GRAVITATION I', '29805', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'SW 218', 'V. Kostelecky', 10, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('PHYS-P 640', 'SUBATOMIC PHYSICS I', '2882', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'SW 217', 'Ryan Mitchell', 9, NULL, 'Lecture', '3', 'SWAIN WEST', ARRAY[]::TEXT[], 'Experimental methods and theorectic description of particle and nuclear physics: applied relativistic quantum mechanics, symmetries of fundamental interactions, experimental techniques, structure of the nucleon, electromagnetic and weak interactions, elementary particles and the Standard Model.', ARRAY[]::TEXT[], NULL),
    ('PHYS-P 704', 'SEMINAR IN NUCLEAR REACTIONS', '2883', 'Class Status', 'F Friday 3:55 PM–5:10 PM', 'HD TBA', 'Chen-Yu Liu', 15, NULL, 'Seminar', '1', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('PHYS-P 705', 'SEM HIGH ENERG PHYS & ELEM PT', '2884', 'Class Status', 'M Monday 3:55 PM–5:10 PM', 'SW 214', 'Sabine Lammers', 15, NULL, 'Seminar', '1', 'SWAIN WEST', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
