    ('PHYS-P 804', 'READINGS IN PROFESSIONAL ETHICS', '8612', 'Class Status', NULL, NULL, 'Mark Messier, James Campbell', 1, NULL, 'Readings', '1', NULL, ARRAY[]::TEXT[], 'Readings in one or more professional areas that present ethical dilemmas. Topics are individualized to the student''s needs and interests. Individual staff guidance.', ARRAY[]::TEXT[], NULL),
