    ('PHYS-S 409', 'APPLIED PHYSICS THESIS', '3729', 'Class Status', NULL, NULL, 'David Baxter', 30, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Under the supervision of a faculty member, students prepare a written thesis that presents previous research work.', ARRAY[]::TEXT[], NULL),
    ('PHYS-X 473', 'APPLIED PHYSICS INTERNSHIP', '3728', 'Class Status', NULL, NULL, 'David Baxter', 30, NULL, 'Independent Study', '1', NULL, ARRAY[]::TEXT[], 'Internship in industry or national laboratory, arranged between the student, the student''s faculty mentor, and internship supervisor.', ARRAY[]::TEXT[], NULL),
    ('PHYS-X 490', 'READINGS IN PHYSICS', '7219', 'Class Status', NULL, NULL, 'Mark Messier', 10, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent reading under supervision of a faculty member. Study in depth of a topic of interest to the student, culminating in a research paper.', ARRAY[]::TEXT[], NULL),
    ('PHYS-X 498', 'RESEARCH PROJECT', '7218', 'Closed', NULL, NULL, 'Mark Messier', 0, NULL, 'Research', '1–6', NULL, ARRAY[]::TEXT[], 'Research participation in group or independent project under the supervision of a faculty member in departmental research areas; or topic agreed upon between the student and supervisor.', ARRAY[]::TEXT[], NULL),
    ('POLS-G 901', 'ADVANCED RESEARCH', '2890', 'Class Status', NULL, NULL, 'Steven Webster', 40, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('POLS-X 299', 'CAREERS FOR POLITICAL SCIENCE STUDENTS', '9387', 'Class Status', 'Th Thursday 6:00 PM–7:30 PM', 'WH 320', 'Christine Barbour', 3, NULL, 'Colloquium', '1', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Through presentations and discussions with IU alumni with professional careers in law, government, business, non-profits and research institutes, international service, polling, and other fields, introduces various career options available to political scientists as well as how to write a resume and excel in interviews for such opportunities.', ARRAY[]::TEXT[], NULL),
    ('POLS-X 471', 'UNDERGRADUATE TEACHING ASSISTANTSHIP', '34051', 'Class Status', NULL, NULL, 'Christine Barbour', 2, NULL, 'Practicum', '3', NULL, ARRAY[]::TEXT[], 'Faculty-directed participation in the various aspects of academic teaching and research. Students will assist a faculty member in such activities as directing simulations, grading, teaching discussion sections, doing research, etc. Individual assignments will vary by instructor.', ARRAY[]::TEXT[], NULL),
    ('POLS-X 471', 'UNDERGRADUATE TEACHING ASSISTANTSHIP', '4425', 'Class Status', NULL, NULL, 'Dina Spechler', 16, NULL, 'Practicum', '3', NULL, ARRAY[]::TEXT[], 'Faculty-directed participation in the various aspects of academic teaching and research. Students will assist a faculty member in such activities as directing simulations, grading, teaching discussion sections, doing research, etc. Individual assignments will vary by instructor.', ARRAY[]::TEXT[], NULL),
    ('POLS-X 477', 'FIELD EXPERIENCE IN POLITICAL SCIENCE', '7230', 'Class Status', NULL, NULL, 'Jacek Dalecki', 15, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Faculty-directed study of aspects of the political process based on field experience. Directed readings, field research, research papers. Certain internship experiences may require research skills.', ARRAY[]::TEXT[], NULL),
    ('POLS-X 477', 'FIELD EXPERIENCE IN POLITICAL SCIENCE', '9669', 'Class Status', NULL, NULL, 'Christine Barbour', 3, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Faculty-directed study of aspects of the political process based on field experience. Directed readings, field research, research papers. Certain internship experiences may require research skills.', ARRAY[]::TEXT[], NULL),
    ('POLS-X 490', 'UNDERGRADUATE READINGS IN POLITICAL SCIENCE', '7500', 'Class Status', NULL, NULL, 'Jacek Dalecki', 5, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Individual readings and research.', ARRAY[]::TEXT[], NULL),
    ('POLS-Y 100', 'AMERICAN POLITICAL CONTROVERSIES', '2891', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'BH 110', 'Jacek Dalecki', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Explores various controversies in American politics, from the motivations of the American Founders to debates about civil rights and liberties and other public disagreements. Examines what types of arguments have been used in public debate about these controversies and how such arguments can be made effectively.', ARRAY['IUB GenEd S&H credit
