    ('POLS-Y 107', 'INTRODUCTION TO COMPARATIVE POLITICS', '2893', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'BH 110', 'Regina Smyth', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines countries around the world to investigate fundamental questions about politics. Topics include democratic development, promotion of economic prosperity, maintenance of security, and management of ethnic and religious conflict. Critical thinking skills encouraged. Cases for comparison include advanced industrialized democracies, communist and former communist countries, and developing countries.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 109', 'INTRODUCTION TO INTERNATIONAL RELATIONS', '2894', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'SE 140', 'Jun Sudduth', 0, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], NULL, ARRAY['Transfer Indiana Initiative
