COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 200', 'CONTEMPORARY POLITICAL TOPICS', '37311', 'Class Status', 'TuTh Tuesday, Thursday 11:35 AM–2:05 PM', 'AC C114', 'Ore Koren', 19, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Extensive analysis of selected contemporary political problems. Topics vary from semester to semester and are listed in the Schedule of Classes.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 205', 'ANALYZING POLITICS', '3681', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'RB 110', 'Caleb Lucas', 10, NULL, 'Lecture', '3', 'STUDENT RECREATIONAL SPORTS CE', ARRAY[]::TEXT[], 'Introduces the approaches and techniques used to study politics. Includes an introduction to social science language, concepts and critical research skills. Overview of political science research and approaches, including case study, surveys, and model-building. Emphasizes skills such as interpreting the presentation of data in charts, graphs, and tables, and elementary analysis of qualitative and quantitative data.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 211', 'INTRODUCTION TO LAW', '5401', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BH 110', 'Jacek Dalecki', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'An introduction to law an aspect of government and politics, and as a means of dealing with major social problems. Students will study legal reasoning, procedures, and materials, and may compare other nation''s legal systems. The course usually includes a moot court or other forms of simulation.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 212', 'MAKING DEMOCRACY WORK', '9388', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'WH 004', 'Jeffrey Isaac', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Nature and justifications for democratic politics and the problems confronting democracy today. Demise of liberalism in America; rise of identity politics and its significance; racial inequality and the problems of deliberative democracy; problems of political alienation and participation.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 300', 'TOPICS IN CURRENT POLITICS AND GOVERNANCE', '11264', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BH 145', 'Michael Weinman', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'What''s happening in current politics and governance? This course focuses on a contemporary issue or political event or process, covered at a more advanced level than Y200. Topics vary from semester to semester and are listed in the online Schedule of Classes.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 300', 'TOPICS IN CURRENT POLITICS AND GOVERNANCE', '13201', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'WH 111', 'Jeffrey Isaac', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'What''s happening in current politics and governance? This course focuses on a contemporary issue or political event or process, covered at a more advanced level than Y200. Topics vary from semester to semester and are listed in the online Schedule of Classes.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 300', 'TOPICS IN CURRENT POLITICS AND GOVERNANCE', '36890', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'WH 008', 'Petro Kuzyk', 16, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'What''s happening in current politics and governance? This course focuses on a contemporary issue or political event or process, covered at a more advanced level than Y200. Topics vary from semester to semester and are listed in the online Schedule of Classes.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 300', 'TOPICS IN CURRENT POLITICS AND GOVERNANCE', '36891', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 227', 'Petro Kuzyk', 18, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'What''s happening in current politics and governance? This course focuses on a contemporary issue or political event or process, covered at a more advanced level than Y200. Topics vary from semester to semester and are listed in the online Schedule of Classes.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 300', 'TOPICS IN CURRENT POLITICS AND GOVERNANCE', '10087', 'Closed', NULL, NULL, 'Christine Barbour', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'What''s happening in current politics and governance? This course focuses on a contemporary issue or political event or process, covered at a more advanced level than Y200. Topics vary from semester to semester and are listed in the online Schedule of Classes.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 304', 'CONSTITUTIONAL LAW', '9550', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 310', 'Eileen Braman', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'American political powers and structures; selected Supreme Court decisions interpreting American constitutional system.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 311', 'DEMOCRACY AND NATIONAL SECURITY', '12734', 'Class Status', NULL, NULL, 'Barry Zulauf', 2, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], 'Analysis of fundamental tensions between democratic values and the requirements of national security. Topics include homeland security and civil liberties in an age of terror, civil-military relations, oversight of intelligence operations, effects of interventions and wars on democracy abroad and at home, and debates over the morality of United States security policies.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 317', 'VOTING, ELECTIONS, AND PUBLIC OPINION', '14144', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'GA 0001', 'Steven Webster', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Determinants of voting behavior in elections. The nature of public opinion on major domestic and foreign policy issues; development of political ideology; other influences on the voting choices of individuals and the outcomes of elections; relationships among public opinion, elections, and the development of public policy.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 332', 'RUSSIAN POLITICS', '29859', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'GA 1106', 'Regina Smyth', 7, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Political process and government structure in the independent Russian state. Political institutions inherited from tsarist empire and USSR (1917-1991), history of political reform, Gorbachev regime (1985-1991). Political problems of ethnic conflict, creating democratic institutions, transition from socialism to market economy.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 333', 'CHINESE POLITICS', '13202', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'BH 206', 'Jason Wu', 12, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Explores contemporary politics and policy issues in the People''s Republic of China. Influence of revolutionary practice and ideology; analysis of contemporary economic, political and social organizations; examination of policy issues including social reforms, economic growth, and democratization and globalization.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('POLS-Y 337', 'LATIN AMERICAN POLITICS', '29860', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'LH 130', 'Armando Razo', 16, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], NULL, ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture
Class uses IU eTexts'], NULL),
    ('POLS-Y 339', 'MIDDLE EASTERN POLITICS', '29861', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'GA 1122', 'Ibrahim Gemeah', 12, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Political culture and change in selected Middle Eastern and North African countries. Topics include political elites, traditional cultures, modern political ideology, institutions of political control, conflict management, and social reform policies.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('POLS-Y 346', 'POLITICS IN THE DEVELOPING WORLD', '32770', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'SE 140', 'Armando Razo', 0, NULL, 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'Focuses on politics in the developing world (Africa, Asia, Latin America, and the Middle East). Comparison of political history: experiences of colonialism and post-colonial authoritarian systems; political economy, development and globalization; democratization and management of protest and conflict; and interactions with international actors and transnational social movements.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
Class uses IU eTexts'], NULL),
    ('POLS-Y 361', 'CONTEMPORARY THEORIES OF INTERNATIONAL POLITICS', '9492', 'Class Status', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'WH 008', 'Justyna Zajac', 9, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Theories used in the study of international politics: systems theory, field theory, conflict theory, alliance and coalition theories, balance-of-power theories, and an introduction to game and bargaining theory.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 363', 'COMPARATIVE FOREIGN POLICY', '13204', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'WH 002', 'Dina Spechler', 2, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Compares factors that influence foreign policy and the foreign policy process. Focuses on domestic or internal sources of foreign policy behavior, including impact of individual leaders, group decision-making processes, bureaucratic politics, ideology and political culture, historical experience, and type of political system. Classroom simulations are central to the course.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 368', 'RUSSIAN AND SOVIET FOREIGN POLICY', '29865', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'WH 111', 'Dina Spechler', 28, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Behavior of Russia and USSR in world affairs from 1945 to the present. Emphasis on impact of geographic assets and vulnerabilities, historical experience, domestic politics, and the changing international environment.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('POLS-Y 381', 'CLASSICAL POLITICAL THOUGHT', '6507', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'WY 005', 'Aurelian Craiutu', 8, NULL, 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'An exposition and critical analysis of the major political philosophers and philosophical schools from Plato to Machiavelli.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('POLS-Y 383', 'FOUNDATIONS OF AMERICAN POLITICAL THOUGHT', '13205', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WH 121', 'Noah Eber-Schmid', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Explores the evolution of American political ideas from colonization through ratification of the Constitution and its implementation.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 406', 'PROBLEMS IN POLITICAL PHILOSOPHY', '34490', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'WH 008', 'William Scheuerman', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Centers on conflicting interpretations of justice, liberty, and equality, as well as certain problems of democracy, including the tension between majority rules and minority rights, and the correlation of rights and duties. Topics vary.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('POLS-Y 490', 'SENIOR SEMINAR IN POLITICAL SCIENCE', '10471', 'Class Status', 'Th Thursday 9:35 AM–12:05 PM', 'SB 231', 'Eileen Braman', 1, NULL, 'Seminar', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Research paper required. Seminar sessions arranged to present papers for evaluation and criticism by fellow students. Subject matter varies by semester.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('POLS-Y 490', 'SENIOR SEMINAR IN POLITICAL SCIENCE', '12077', 'Class Status', 'W Wednesday 9:35 AM–12:05 PM', 'AC C107', 'William Scheuerman', 2, NULL, 'Seminar', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Research paper required. Seminar sessions arranged to present papers for evaluation and criticism by fellow students. Subject matter varies by semester.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('POLS-Y 490', 'SENIOR SEMINAR IN POLITICAL SCIENCE', '34383', 'Class Status', 'M Monday 3:55 PM–6:25 PM', 'WH 116', 'William Bianco', 5, NULL, 'Seminar', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Research paper required. Seminar sessions arranged to present papers for evaluation and criticism by fellow students. Subject matter varies by semester.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('POLS-Y 490', 'SENIOR SEMINAR IN POLITICAL SCIENCE', '6617', 'Closed', 'Tu Tuesday 12:45 PM–3:15 PM', 'AC C107', 'Judith Failer', 0, NULL, 'Seminar', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Research paper required. Seminar sessions arranged to present papers for evaluation and criticism by fellow students. Subject matter varies by semester.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('POLS-Y 499', 'HONORS THESIS', '7855', 'Class Status', 'W Wednesday 12:45 PM–2:45 PM', 'WH 108', 'Lizzie Brannon', 4, NULL, 'Independent Study', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], NULL, ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('POLS-Y 557', 'COMPARATIVE POLITICS: APPROACHES AND ISSUES', '14384', 'Class Status', 'Th Thursday 11:10 AM–1:40 PM', 'WH 218', 'Jason Wu', 3, NULL, 'Seminar', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Overview and analysis of the approaches and issues in the literature of comparative politics. Required of students taking comparative politics as a field of study for the Ph.D. It is recommended that this course be taken during the first two years of graduate work at Indiana University.', ARRAY[]::TEXT[], NULL),
    ('POLS-Y 569', 'INTERNATIONAL RELATIONS: APPROACHES AND ISSUES', '34455', 'Closed', 'M Monday 9:35 AM–12:05 PM', 'WH 218', 'Jun Sudduth', 0, NULL, 'Seminar', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Overview and analysis of the approaches and issues in het literature of international relations. Required of students taking international relations as a field of study for the Ph.D. It is recommended that this course bet taken during the first two years of graduate work at Indiana University.', ARRAY[]::TEXT[], NULL),
    ('POLS-Y 570', 'INTRODUCTION TO THE STUDY OF POLITICS', '9061', 'Class Status', 'W Wednesday 9:35 AM–12:05 PM', 'WH 218', 'Steven Webster', 4, NULL, 'Seminar', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Problems of graduate study and professional scholarship; central organizing concepts and the use of theory in political science and related disciplines; specialized areas of research and scholarship in political science; conditions of scientific inquiry and methodological problems in the study of political phenomena; central importance of theory in explanation.', ARRAY[]::TEXT[], NULL),
    ('POLS-Y 575', 'POLITICAL DATA ANALYSIS I', '9399', 'Class Status', 'M Monday 3:55 PM–6:25 PM', 'WH 108', 'Caleb Lucas', 9, NULL, 'Seminar', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Basic quantitative analysis techniques applied to political science data: principles of measurement, tables, graphs, probability distributions, nonparametric statistics, matrix algebra, Markov chains, correlation and simple regression, tests of significance. Computer processing of data and applications of bivariate statistics to problems in political science are emphasized.', ARRAY[]::TEXT[], NULL),
    ('POLS-Y 657', 'COMPARATIVE POLITICS', '35281', 'Class Status', NULL, 'OL ONLINE', 'Jean Abshire', 1, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], '(The focus may be on one or more political systems within regions indicated.) Illustrative topics: political elites and social stratification, comparative administration and public policy, cross-national analysis, West Europe, East Europe, comparative Communist systems, Russia, Africa, Middle East, Latin America, East Asia, comparative development strategies.', ARRAY[]::TEXT[], NULL),
    ('POLS-Y 657', 'COMPARATIVE POLITICS', '34692', 'Closed', NULL, 'OL ONLINE', 'Jean Abshire', 0, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], '(The focus may be on one or more political systems within regions indicated.) Illustrative topics: political elites and social stratification, comparative administration and public policy, cross-national analysis, West Europe, East Europe, comparative Communist systems, Russia, Africa, Middle East, Latin America, East Asia, comparative development strategies.', ARRAY[]::TEXT[], NULL),
    ('POLS-Y 661', 'AMERICAN POLITICS', '12078', 'Class Status', 'Th Thursday 3:55 PM–6:25 PM', 'WH 218', 'Rachel Lienesch', 3, NULL, 'Seminar', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Illustrative topics: the Presidency, legislative process, political behavior, political parties and representation, political socialization, comparative state politics, urban politics, interest group politics.', ARRAY[]::TEXT[], NULL),
    ('POLS-Y 673', 'EMPIRICAL THEORY AND METHODOLOGY', '34825', 'Class Status', 'Tu Tuesday 3:00 PM–5:00 PM', 'HD TBA', 'Jessica Steinberg', 2, NULL, 'Seminar', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Illustrative topics: survey of empirical theory; theory building and causal inference; positive political theory; institutional analysis and design; empirical democratic theory.', ARRAY[]::TEXT[], NULL),
    ('POLS-Y 675', 'POLITICAL PHILOSOPHY', '3421', 'Closed', 'Tu Tuesday 3:55 PM–6:25 PM', 'WH 218', 'Noah Eber-Schmid', 0, NULL, 'Seminar', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Illustrative topics: analysis of political concepts; political theory of the Enlightenment; 19th century political thought; welfare state; theory and practice; Marxist theory.', ARRAY[]::TEXT[], NULL),
